//

import Foundation
import FactoryKit
import CoreLocation

/// Создание маркера
protocol TrackMarkerCreateUseCase {
    /// Создание нового маркера
    /// - Parameters:
    ///   - location: геопозиция
    ///   - countRate: скорость счет
    ///   - doseRate: мощность дозы
    ///   - track: трэк
    /// - Returns: Маркер
    func createMarker(location: CLLocation, countRate: Float, doseRate: Float, track: Track) async -> TrackMarker
}

final class TrackMarkerCreateUseCaseImpl: TrackMarkerCreateUseCase {

    @Injected(\.trackMarkerRepository) private var trackMarkerRepository
    @Injected(\.trackRepository) private var trackRepository

    func createMarker(location: CLLocation, countRate: Float, doseRate: Float, track: Track) async -> TrackMarker {
        let marker = await trackMarkerRepository.createMarker(
            latitude: location.coordinate.latitude,
            longitude: location.coordinate.longitude,
            accuarcy: location.horizontalAccuracy,
            timestamp: Date.now.toMilliseconds,
            countRate: countRate,
            doseRate: doseRate,
            trackId: track.id
        )
        track.markers.insert(marker)

        var newPeakDoseRate: Float?
        var newPeakCountRate: Float?

        if countRate > track.peakCountRate {
            newPeakCountRate = countRate
        }

        if doseRate > track.peakDoseRate {
            newPeakDoseRate = doseRate
        }

        if newPeakDoseRate != nil || newPeakCountRate != nil {
            await trackRepository.update(.peak(countRate: newPeakCountRate, doseRate: newPeakDoseRate), trackId: track.id)
        }

        return marker
    }
}

//
//  Track.swift
//  Radiacode
//
//  Created by Matvey Kozin on 08.08.2024.
//

import Foundation

@Observable
final class Track: Identifiable, Equatable {
    /// id базы данных
    let id: String
    /// Название
    var title: String
    /// Устроства записи трека (массив для объеденения треков)
    var devices: Set<RadiaCode.Device>
    /// Начало записи трека
    let startDate: Date
    /// Признак того что трэк закончен
    var isFinished: Bool

    /// Маркеры
    var markers: Set<TrackMarker> = .init() {
        didSet {
            Task.detached { [weak self] in
                await self?.fillPeaks()
            }
        }
    }

    /// Периоды
    var periods: [TrackPeriod]
    /// Пиковое значение Count Rate
    var peakCountRate: Float
    /// Пиковое значение Dose Rate
    var peakDoseRate: Float
    /// Комментарий
    var comment: String?

    init(
        id: String,
        title: String,
        devices: Set<RadiaCode.Device>,
        startDate: Date,
        isFinished: Bool,
        periods: [TrackPeriod],
        peakCountRate: Float,
        peakDoseRate: Float,
        comment: String?
    ) {
        self.id = id
        self.title = title
        self.devices = devices
        self.startDate = startDate
        self.isFinished = isFinished
        self.periods = periods
        self.peakDoseRate = peakDoseRate
        self.peakCountRate = peakCountRate
        self.comment = comment
    }

    static func == (lhs: Track, rhs: Track) -> Bool {
        lhs.id == rhs.id
    }

    private func fillPeaks() async {
        let copy = await MainActor.run { markers }

        let maxValues = copy.reduce(into: (doseRate: Float.zero, countRate: Float.zero)) { result, marker in
            result.doseRate = max(result.doseRate, marker.doseRate)
            result.countRate = max(result.countRate, marker.countRate)
        }

        await MainActor.run {
            if self.peakCountRate != maxValues.countRate {
                self.peakCountRate = maxValues.countRate
            }
            if self.peakDoseRate != maxValues.doseRate {
                self.peakDoseRate = maxValues.doseRate
            }
        }
    }
}

extension Track {

    @ObservationIgnored
    var activePeriod: TrackPeriod? {
        periods.first(where: { $0.endDate == nil })
    }

    @ObservationIgnored
    var totalTime: UInt32 {
        periods.map { $0.time }.reduce(0, +)
    }

    @ObservationIgnored
    var totalDistance: Double {
        periods.map { $0.distance }.reduce(0, +)
    }
}

extension Track {
    static let mockActive = Track(id: "as", title: "Mock Non active", devices: .init(), startDate: .now, isFinished: false, periods: [.init(id: "", startDate: 2, endDate: 10, distance: 10)], peakCountRate: 10, peakDoseRate: 10, comment: nil)
    static let mockFinished = Track(id: "as", title: "Mock Finished", devices: .init(), startDate: .now, isFinished: true, periods: [.init(id: "", startDate: 2, endDate: 10, distance: 10)], peakCountRate: 10, peakDoseRate: 10, comment: nil)
}

content.text:
Found the root cause. `Track` is `@Observable` and its `markers: Set<TrackMarker>` is expected to be mutated on the `MainActor`, but `createMarker` is a plain `async` function that runs on a background executor — so line 39 mutates the Set off the main thread, causing a data race / `KERN_INVALID_ADDRESS` during `Set.resize`.

The fix is to wrap the mutation in `await MainActor.run`:

```swift
// TrackMarkerCreateUseCase.swift:39
await MainActor.run {
    track.markers.insert(marker)
}
```

Want me to apply that?

